const raw = JSON.parse(results[1]); const action = vars.action || 'copy'; 

// Helpers
function keyTime(k) { const v = k.frame ?? k.time ?? k.seconds ?? k.position ?? k.frameNumber ?? 0; const n = Number(v); return isNaN(n) ? 0 : n; }
function stableId(k) { return String(k.keyframeId || k.id || '') + String(k.objectId || '') + String(k.propertyKey || ''); }
function sortedKeyframes(data) { let out = []; if (data.keyframes && typeof data.keyframes === 'object') { for (const [aid, arr] of Object.entries(data.keyframes)) (arr || []).forEach((k, idx) => out.push(Object.assign({_animationId: aid, _sourceIndex: idx}, k))); } out.sort((a, b) => keyTime(a) - keyTime(b) || stableId(a).localeCompare(stableId(b))); return out; }

const kfs = sortedKeyframes(raw);
if (!kfs.length) throw new Error(action === 'paste' ? 'Select target keyframes first.' : 'Select source keyframes first.');

setVar('animationId', kfs[0]._animationId || '');
setVar('selectedKeyframes', kfs);

if (action === 'paste') {
  // MODE PASTE: Reload EVERYTHING from localStorage
  const saved = localStorage.getItem('rivebar.copyPasteCurves');
  if (!saved) throw new Error('No curves copied yet. Click "Copy" first.');

  const clip = JSON.parse(saved);
  if (!clip.curves || clip.curves.length === 0) throw new Error('Copied data is empty or invalid.');

  setVar('copiedCurves', clip.curves);

  // Restore queryKeys from clip or reconstruct
  const pkeys = {};
  if (clip.queryKeys) {
     Object.assign(pkeys, clip.queryKeys);
  } else {
     kfs.forEach(k => { 
       if (k.objectId && k.propertyKey !== undefined && k.propertyKey !== null) { 
         const id = String(k.objectId); const key = Number(k.propertyKey); 
         if (!pkeys[id]) pkeys[id] = []; 
         if (!pkeys[id].includes(key)) pkeys[id].push(key); 
       } 
     });
  }
  setVar('queryKeys', pkeys);

} else {
  // MODE COPY: Prepare data to save
  const curves = [];
  const pkeys = {};

  kfs.forEach((k, order) => {
    curves.push({ 
      interpolationType: k.interpolationType || 'cubic', 
      interpolatorId: k.interpolatorId || null, 
      sourceTime: keyTime(k), 
      sourceOrder: order 
    });

    if (k.interpolatorId) {
      pkeys[k.interpolatorId] = [63, 64, 65, 66];
    } else if (k.objectId && k.propertyKey !== undefined && k.propertyKey !== null) {
      const id = String(k.objectId); 
      const key = Number(k.propertyKey); 
      if (!pkeys[id]) pkeys[id] = []; 
      if (!pkeys[id].includes(key)) pkeys[id].push(key); 
    }
  });

  setVar('srcCurves', curves);
  setVar('queryKeys', pkeys);
}

const action = vars.action || 'copy';

if (action === 'copy') {
  // --- COPY LOGIC ---
  let resp = {}; 
  try { resp = JSON.parse(results[3] || '{}'); } catch(e) {}
  const vals = resp.values || resp || {};
  const curves = vars.srcCurves || [];

  // Inject cubic params
  curves.forEach(c => { 
    if (c.interpolatorId && vals[c.interpolatorId]) { 
      const v = vals[c.interpolatorId]; 
      c.cubicParams = { x1: v['63'] ?? 0, y1: v['64'] ?? 0, x2: v['65'] ?? 1, y2: v['66'] ?? 1 }; 
    } else if (!c.cubicParams) { 
      c.cubicParams = { x1: 0.42, y1: 0, x2: 0.58, y2: 1 }; 
    } 
  });

  // Save to storage
  const clip = { 
    version: 1, 
    copiedAt: Date.now(), 
    count: curves.length, 
    curves: curves, 
    queryKeys: vars.queryKeys || {} 
  };
  localStorage.setItem('rivebar.copyPasteCurves', JSON.stringify(clip));

  setVar('toastText', 'Copied ' + curves.length + ' curve(s)');

} else {
  // --- PASTE LOGIC ---
  const targets = vars.selectedKeyframes || [];
  const src = vars.copiedCurves || [];

  if (src.length === 0) throw new Error('Internal error: Copied data not found.');

  const changes = targets.map((k, i) => { 
    const c = src[i % src.length]; 
    return { 
      keyframeId: k.keyframeId, 
      interpolationType: c.interpolationType || 'cubic', 
      cubicParams: c.cubicParams || { x1: 0.42, y1: 0, x2: 0.58, y2: 1 } 
    }; 
  });

  setVar('finalCommand', 'modifyKeyFrames');
  setVar('finalData', { 
    modifyKeyFrames: { 
      animationId: vars.animationId, 
      change: changes 
    } 
  });

  setVar('toastText', 'Pasted ' + targets.length + ' curve(s)');
}
